  static MexicoStatePath? findByAbbreviation(String abbr) {
    try {
      return states.firstWhere(
        (s) => s.abbreviation.toUpperCase() == abbr.toUpperCase(),
      );
    } catch (_) {
      return null;
    }
  }

  static MexicoStatePath? findByName(String name) {
    try {
      return states.firstWhere(
        (s) => s.name.toLowerCase() == name.toLowerCase(),
      );
    } catch (_) {
      return null;
    }
  }
}